// FloatingNewsletter.js
import React, { useState } from 'react';
import './FloatingNewsletter.css';
import { FaCheck } from 'react-icons/fa';

export default function FloatingNewsletter() {
  const [showPopup, setShowPopup] = useState(false);
  const [email, setEmail] = useState('');
  const [subscribed, setSubscribed] = useState(false);
  const [fadeIn, setFadeIn] = useState(false);

  const handleSubscribe = () => {
    if (!email || !email.includes('@')) return;
    setSubscribed(true);
    setTimeout(() => setShowPopup(false), 1500);
  };

  const openPopup = () => {
    setShowPopup(true);
    setSubscribed(false);
    setEmail('');
    setFadeIn(true);
  };

  return (
    <div>
      <button className="newsletter-launch-button" onClick={openPopup}>
        Join Newsletter
      </button>

      {showPopup && (
        <div className={`newsletter-popup ${fadeIn ? 'fade-in' : ''}`}>
          {!subscribed ? (
            <>
              <input
                type="email"
                placeholder="Enter your email..."
                value={email}
                onChange={(e) => setEmail(e.target.value)}
              />
              <button onClick={handleSubscribe} className="check-button">
                <FaCheck />
              </button>
            </>
          ) : (
            <div className="subscribed-text">Thank you! 💌</div>
          )}
        </div>
      )}
    </div>
  );
}
